import{c as s,a7 as n,y as e,B as l}from"./chunks/framework.BYQtDGaq.js";const b=JSON.parse('{"title":"SGLang 服务器参数配置","description":"全面整理 SGLang 服务器的模型路径、并行策略、调度及内存管理等核心启动参数配置说明。","frontmatter":{"title":"SGLang 服务器参数配置","description":"全面整理 SGLang 服务器的模型路径、并行策略、调度及内存管理等核心启动参数配置说明。"},"headers":[],"relativePath":"inference/sglang/server-parameters.md","filePath":"inference/sglang/server-parameters.md","lastUpdated":1782703478000}'),i={name:"inference/sglang/server-parameters.md"};function t(r,a,p,d,c,o){return n(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="sglang-服务器参数配置" tabindex="-1">SGLang 服务器参数配置 <a class="header-anchor" href="#sglang-服务器参数配置" aria-label="Permalink to “SGLang 服务器参数配置”">​</a></h1><h2 id="基础配置参数详解" tabindex="-1">基础配置参数详解 <a class="header-anchor" href="#基础配置参数详解" aria-label="Permalink to “基础配置参数详解”">​</a></h2><h3 id="模型与路径配置" tabindex="-1">模型与路径配置 <a class="header-anchor" href="#模型与路径配置" aria-label="Permalink to “模型与路径配置”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>--model-path /mnt/models/DeepSeek-R1  # 模型文件路径</span></span>
<span class="line"><span>--tokenizer-path /mnt/models/tokenizer  # 分词器路径</span></span>
<span class="line"><span>--load-format gguf  # 模型加载格式（GGUF/PyTorch）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><strong>关键点</strong>：路径需具备可读权限，模型与分词器版本需严格匹配，避免因版本冲突导致初始化失败。</li></ul><h3 id="设备与并行策略" tabindex="-1">设备与并行策略 <a class="header-anchor" href="#设备与并行策略" aria-label="Permalink to “设备与并行策略”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>--device cuda  # 设备类型（GPU/CPU）</span></span>
<span class="line"><span>--tp 4         # 张量并行度</span></span>
<span class="line"><span>--dp-size 2    # 数据并行度</span></span>
<span class="line"><span>--ep-size 1    # 专家并行度（MoE 模型专用）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li><strong>配置建议</strong>：8 卡服务器推荐 <code>--tp 4 --dp-size 2</code>，显存不足时优先降低 <code>--tp</code> 值。</li></ul><h2 id="关键性能参数优化" tabindex="-1">关键性能参数优化 <a class="header-anchor" href="#关键性能参数优化" aria-label="Permalink to “关键性能参数优化”">​</a></h2><h3 id="内存与显存管理" tabindex="-1">内存与显存管理 <a class="header-anchor" href="#内存与显存管理" aria-label="Permalink to “内存与显存管理”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>--mem-fraction-static 0.85  # 静态显存分配比例</span></span>
<span class="line"><span>--kv-cache-dtype auto       # 键值缓存数据类型（fp16/bf16/auto）</span></span>
<span class="line"><span>--max-total-tokens 128000   # 最大上下文总 Token 数</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li>优化策略：显存不足时，按优先级调整参数： <ol><li>降低 <code>--max-total-tokens</code> 至 102400</li><li>启用量化 <code>--quantization fp8</code></li><li>减少 <code>--mem-fraction-static</code> 至 0.8</li></ol></li></ul><h3 id="请求处理控制" tabindex="-1">请求处理控制 <a class="header-anchor" href="#请求处理控制" aria-label="Permalink to “请求处理控制”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>--max-running-requests 16      # 并发请求上限</span></span>
<span class="line"><span>--max-prefill-tokens 8192      # 首轮生成最大 Token 数</span></span>
<span class="line"><span>--chunked-prefill-size 2048    # 分块预填充大小</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><strong>高并发场景</strong>：增加 <code>--max-running-requests</code> 至 32，同时监控 GPU 利用率（目标值 70%-90%）。</li></ul><h2 id="生产环境优化方案" tabindex="-1">生产环境优化方案 <a class="header-anchor" href="#生产环境优化方案" aria-label="Permalink to “生产环境优化方案”">​</a></h2><h3 id="调度与负载均衡" tabindex="-1">调度与负载均衡 <a class="header-anchor" href="#调度与负载均衡" aria-label="Permalink to “调度与负载均衡”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>--schedule-policy lpm                   # 调度策略（lpm/fcfs）</span></span>
<span class="line"><span>--load-balance-method round-robin       # 负载均衡方式</span></span>
<span class="line"><span>--dist-init-addr 192.168.1.100:29500    # 多节点通信地址</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li>多机部署要求 <ul><li>网络延迟 &lt;1ms</li><li>防火墙开放 29500 端口</li><li>使用 <code>--nnodes 3 --node-rank 0</code> 指定节点角色</li></ul></li></ul><h3 id="量化与推理加速" tabindex="-1">量化与推理加速 <a class="header-anchor" href="#量化与推理加速" aria-label="Permalink to “量化与推理加速”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>--quantization fp8                  # 启用 FP8 量化</span></span>
<span class="line"><span>--attention-backend flashinfer      # 优化注意力计算</span></span>
<span class="line"><span>--triton-attention-num-kv-splits 4  # Triton 注意力 KV 分割数</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><p>量化效果：</p><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">显存占用</th><th style="text-align:left;">精度损失</th></tr></thead><tbody><tr><td style="text-align:left;">FP32</td><td style="text-align:left;">100%</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:left;">FP8</td><td style="text-align:left;">45%</td><td style="text-align:left;">&lt;2%</td></tr></tbody></table></div></li></ul><h2 id="调试与监控体系" tabindex="-1">调试与监控体系 <a class="header-anchor" href="#调试与监控体系" aria-label="Permalink to “调试与监控体系”">​</a></h2><h3 id="日志与指标" tabindex="-1">日志与指标 <a class="header-anchor" href="#日志与指标" aria-label="Permalink to “日志与指标”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>--log-level info                  # 日志级别</span></span>
<span class="line"><span>--enable-metrics true             # 启用 Prometheus 指标</span></span>
<span class="line"><span>--metrics-port 8008               # 指标暴露端口</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li>关键监控指标： <ul><li><code>sglang_requests_total</code>：请求总数</li><li><code>sglang_gpu_utilization</code>：GPU 利用率</li><li><code>sglang_kv_cache_usage</code>：KV 缓存使用率</li></ul></li></ul><h3 id="调试工具" tabindex="-1">调试工具 <a class="header-anchor" href="#调试工具" aria-label="Permalink to “调试工具”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>--debug-tensor-dump-output-folder /tmp/debug     # 张量转储目录</span></span>
<span class="line"><span>--enable-nan-detection true                      # 检测 NaN 值</span></span>
<span class="line"><span>--warmups 3                                      # 预热请求数</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li>故障排查流程： <ol><li>启用<code>--log-level debug</code></li><li>检查张量转储文件</li><li>验证输入数据有效性</li></ol></li></ul><h2 id="完整配置示例" tabindex="-1">完整配置示例 <a class="header-anchor" href="#完整配置示例" aria-label="Permalink to “完整配置示例”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>python3 -m sglang.launch_server \\</span></span>
<span class="line"><span>  --model-path /mnt/models/DeepSeek-R1 \\</span></span>
<span class="line"><span>  --host 0.0.0.0 \\</span></span>
<span class="line"><span>  --port 4000 \\</span></span>
<span class="line"><span>  --device cuda \\</span></span>
<span class="line"><span>  --tp 4 \\</span></span>
<span class="line"><span>  --dp-size 2 \\</span></span>
<span class="line"><span>  --mem-fraction-static 0.8 \\</span></span>
<span class="line"><span>  --max-running-requests 32 \\</span></span>
<span class="line"><span>  --quantization fp8 \\</span></span>
<span class="line"><span>  --attention-backend flashinfer \\</span></span>
<span class="line"><span>  --enable-metrics true \\</span></span>
<span class="line"><span>  --log-level info</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h2 id="常见问题解决方案" tabindex="-1">常见问题解决方案 <a class="header-anchor" href="#常见问题解决方案" aria-label="Permalink to “常见问题解决方案”">​</a></h2><h3 id="oom-错误处理" tabindex="-1">OOM 错误处理 <a class="header-anchor" href="#oom-错误处理" aria-label="Permalink to “OOM 错误处理”">​</a></h3><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">错误类型</th><th style="text-align:left;">解决方案</th></tr></thead><tbody><tr><td style="text-align:left;">显存溢出</td><td style="text-align:left;">降低 <code>--mem-fraction-static</code> 至 0.75</td></tr><tr><td style="text-align:left;">内存不足</td><td style="text-align:left;">减少 <code>--max-total-tokens</code> 至 96000</td></tr><tr><td style="text-align:left;">KV 缓存满</td><td style="text-align:left;">增加 <code>--kv-cache-size</code> 参数</td></tr></tbody></table></div><h3 id="多节点同步失败" tabindex="-1">多节点同步失败 <a class="header-anchor" href="#多节点同步失败" aria-label="Permalink to “多节点同步失败”">​</a></h3><ol><li>检查 <code>--dist-init-addr</code> 网络可达性</li><li>验证防火墙规则：<code>sudo ufw allow 29500</code></li><li>使用 <code>--nnodes</code> 和 <code>--node-rank</code> 明确节点角色</li></ol>`,36)])])}const u=s(i,[["render",t]]);export{b as __pageData,u as default};
